#include <iostream>
#include <vector>

using namespace std;

int main() {
  vector<int> prices = {100, 102, 104, 106, 108, 110, 108, 112, 114, 116};
  int windowSize = 5;
  vector<int> movingAverage = calculateMovingAverage(prices, windowSize);

  for (int i = 0; i < movingAverage.size(); i++) {
    cout << movingAverage[i] << endl;
  }

  return 0;
}

vector<int> calculateMovingAverage(vector<int> prices, int windowSize) {
  vector<int> movingAverage(prices.size());

  for (int i = 0; i < prices.size(); i++) {
    int sum = 0;
    for (int j = 0; j < windowSize; j++) {
      if (i - j >= 0) {
        sum += prices[i - j];
      }
    }
    movingAverage[i] = sum / windowSize;
  }

  return movingAverage;
}
```

